INSERT INTO public."CategoryTranslation" (id, "categoryId", locale, title, slug, "introHtml", "faqJson", "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('43b83550-c277-4c6a-9ba5-0d58856f379d', 'cat-diblong-main', 'sl', 'Diblong linija', 'diblong-linija', '<p>Izbrana linija zeliščnih izdelkov za zrelo, elegantno doživetje vsakdana. Teksture in formule so prilagojene ritualu nege.</p>', '[{"q":{"sl":"Ali so izdelki diskretno pakirani?","en":"Is packaging discreet?","hr":"Je li pakiranje diskretno?"},"a":{"sl":"Da — nevpadljiva pošiljka brez opisnih oznak vsebine.","en":"Yes — neutral outer packaging without descriptive markings.","hr":"Da — neutralno vanjsko pakiranje bez opisnih oznaka."}}]', 'Kategorija Diblong | Premium intimna nega', 'Odkrijte Diblong linijo: zeliščni rituali nege v premium izvedbi.', 'Diblong linija', 'Premium zeliščna linija za intimno dobrobit.', NULL, '/sl/kategorija/diblong-linija');
INSERT INTO public."CategoryTranslation" (id, "categoryId", locale, title, slug, "introHtml", "faqJson", "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('27a2e939-a223-47b0-b30c-1227c9232a90', 'cat-diblong-main', 'en', 'Diblong line', 'diblong-line', '<p>A curated herbal line for a mature, elegant daily ritual. Textures and formulas support mindful care.</p>', '[{"q":{"sl":"Ali so izdelki diskretno pakirani?","en":"Is packaging discreet?","hr":"Je li pakiranje diskretno?"},"a":{"sl":"Da — nevpadljiva pošiljka brez opisnih oznak vsebine.","en":"Yes — neutral outer packaging without descriptive markings.","hr":"Da — neutralno vanjsko pakiranje bez opisnih oznaka."}}]', 'Diblong category | Premium intimate care', 'Explore the Diblong line — herbal rituals in a premium expression.', 'Diblong line', 'Premium herbal line for intimate wellness.', NULL, '/en/category/diblong-line');
INSERT INTO public."CategoryTranslation" (id, "categoryId", locale, title, slug, "introHtml", "faqJson", "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('2bd6dff8-077b-489d-a7f0-a213d65d0f9a', 'cat-diblong-main', 'hr', 'Diblong linija', 'diblong-linija', '<p>Odabrana biljna linija za zrelo, elegantno svakodnevicu. Teksture i formule podržavaju njegu kao ritual.</p>', '[{"q":{"sl":"Ali so izdelki diskretno pakirani?","en":"Is packaging discreet?","hr":"Je li pakiranje diskretno?"},"a":{"sl":"Da — nevpadljiva pošiljka brez opisnih oznak vsebine.","en":"Yes — neutral outer packaging without descriptive markings.","hr":"Da — neutralno vanjsko pakiranje bez opisnih oznaka."}}]', 'Diblong linija | Premium intimna njega', 'Otkrijte Diblong liniju — biljni rituali u premium izvedbi.', 'Diblong linija', 'Premium biljna linija za intimnu dobrobit.', NULL, '/hr/kategorija/diblong-linija');
