INSERT INTO public."PageTranslation" (id, "pageId", locale, title, slug, "bodyHtml", "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('35c3b837-0a67-4590-8ed1-44c4fa6ef952', '6172062c-9f51-44e3-9b19-f367bf6c0109', 'sl', 'O znamki', 'o-znamki', '<p>Diblong je globalna znamka odraslih zeliščnih izdelkov, zasnovana za diskretno, elegantno doživetje intimnega dobrega počutja. Naša oblika, vonj in tekstura so skrbno uravnoteženi za sodoben, premičen življenjski slog.</p>', 'O znamki | Diblong', 'Diblong — o znamki in filozofiji premium intimne nege.', 'O znamki', 'Diblong — o znamki in filozofiji premium intimne nege.', NULL, '/sl/o-znamki');
INSERT INTO public."PageTranslation" (id, "pageId", locale, title, slug, "bodyHtml", "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('83e0c302-bc76-411c-bdfa-dcb087596b26', '6172062c-9f51-44e3-9b19-f367bf6c0109', 'en', 'About the brand', 'about', '<p>Diblong is a global adult herbal brand crafted for discreet, elegant intimate wellness. Form, aroma, and texture are balanced for a modern, premium lifestyle.</p>', 'About the brand | Diblong', 'Diblong — brand story and philosophy of premium intimate care.', 'About the brand', 'Diblong — brand story and philosophy of premium intimate care.', NULL, '/en/about');
INSERT INTO public."PageTranslation" (id, "pageId", locale, title, slug, "bodyHtml", "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('b4cdeb77-d0f0-4056-bfa1-6549f33fb30e', '6172062c-9f51-44e3-9b19-f367bf6c0109', 'hr', 'O brendu', 'o-brendu', '<p>Diblong je globalni biljni brend za odrasle, oblikovan za diskretno, elegantno intimno dobrobit. Tekstura i nota pažljivo su uravnotežene za suvremeni, premium životni stil.</p>', 'O brendu | Diblong', 'Diblong — priča o brendu i filozofiji premium intimne njege.', 'O brendu', 'Diblong — priča o brendu i filozofiji premium intimne njege.', NULL, '/hr/o-brendu');
INSERT INTO public."PageTranslation" (id, "pageId", locale, title, slug, "bodyHtml", "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('a9d0e3c3-3202-4818-9838-45f932318bd1', '563196ce-a814-4cbf-bcd7-fd8548f34bf4', 'sl', 'Pogosta vprašanja', 'pogosta-vprasanja', '<p>Odgovori na najpogostejša vprašanja o naročilih, dostavi in zasebnosti.</p>', 'Pogosta vprašanja | Diblong', 'Pogosta vprašanja — Diblong trgovina.', 'Pogosta vprašanja', 'Pogosta vprašanja — Diblong trgovina.', NULL, '/sl/pogosta-vprasanja');
