INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('0845abd6-a7a6-4604-9aeb-b9544f3a3db0', '214399ed-8ca6-404c-bd35-89208c8610bf', 'sl', 'Diblong Drink', 'diblong-drink', 'Uravnotežena pijača za večerno umiritev in zrelo doživetje.', '<p>Subtilna nota zelišč in elegantna sladkoba ustvarita za trenutke, ko želite počasnejši ritem. Priporočamo zmernost in spoštovanje osebnih meja.</p>', 'Servirajte ohlajeno. Ne mešajte z alkoholom, če ste občutljivi na stimulacije.', NULL, 'Prehransko dopolnilo ni nadomestek za uravnoteženo prehrano. Shranjujte izven dosega otrok.', 'Diblong Drink | Diblong', 'Uravnotežena pijača za večerno umiritev in zrelo doživetje.', 'Diblong Drink', 'Uravnotežena pijača za večerno umiritev in zrelo doživetje.', NULL, '/sl/izdelek/diblong-drink');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('22aac329-d6e9-4975-980d-9f5ed6b989b5', '214399ed-8ca6-404c-bd35-89208c8610bf', 'en', 'Diblong Drink', 'diblong-drink', 'A balanced drink for evening ease and a mature, composed mood.', '<p>Subtle herbal notes and refined sweetness for moments when you want a slower rhythm. Moderation and personal boundaries matter.</p>', 'Serve chilled. Avoid mixing with alcohol if you are stimulation-sensitive.', NULL, 'Food supplement is not a substitute for a balanced diet. Keep away from children.', 'Diblong Drink | Diblong', 'A balanced drink for evening ease and a mature, composed mood.', 'Diblong Drink', 'A balanced drink for evening ease and a mature, composed mood.', NULL, '/en/product/diblong-drink');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('b91eafa4-90a7-451b-ab85-d053fbdf4158', '214399ed-8ca6-404c-bd35-89208c8610bf', 'hr', 'Diblong Drink', 'diblong-drink', 'Uravnoteženo piće za večernje smirivanje i zrelo iskustvo.', '<p>Suptilne biljne note i elegantna slatkoća za trenutke sporijeg ritma. Umjerenost i osobne granice su bitne.</p>', 'Poslužite ohlađeno. Izbjegavajte miješanje s alkoholom ako ste osjetljivi.', NULL, 'Dodatak prehrani nije zamjena za uravnoteženu prehranu. Čuvati izvan dosega djece.', 'Diblong Drink | Diblong', 'Uravnoteženo piće za večernje smirivanje i zrelo iskustvo.', 'Diblong Drink', 'Uravnoteženo piće za večernje smirivanje i zrelo iskustvo.', NULL, '/hr/proizvod/diblong-drink');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('89521416-ef7f-42a6-85f7-96b79526a424', 'b7b04cbf-1ecc-4979-848c-fad81e474084', 'sl', 'Diblong Shot', 'diblong-shot', 'Kompaktna izkušnja — intenzivna aromatičnost v elegantnem formatu.', '<p>Shot oblika je zasnovana za hitro pripravo in diskretno uživanje. Tekstura je gladka, okus pa uravnotežen, da ohranja premičen ton znamke.</p>', 'Zaužijte neposredno iz stekleničke. Priporočena količina: 1 način uporabe na dogodek.', NULL, 'Ni primeren za nosečnice in mladoletnike. Pri zdravstvenih težavah se posvetujte z zdravnikom.', 'Diblong Shot | Diblong', 'Kompaktna izkušnja — intenzivna aromatičnost v elegantnem formatu.', 'Diblong Shot', 'Kompaktna izkušnja — intenzivna aromatičnost v elegantnem formatu.', 'https://diblong.com/assets/images/shot-yazi-yani.webp', '/sl/izdelek/diblong-shot');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('dd487608-2564-4344-b8c2-13a6339e9a06', 'b7b04cbf-1ecc-4979-848c-fad81e474084', 'en', 'Diblong Shot', 'diblong-shot', 'A compact experience — aromatic intensity in an elegant format.', '<p>The shot format is designed for quick preparation and discreet enjoyment. Smooth texture, balanced taste, premium tone.</p>', 'Consume directly from the vial. Recommended: single serving per occasion.', NULL, 'Not suitable for pregnancy or minors. Consult a clinician if you have health concerns.', 'Diblong Shot | Diblong', 'A compact experience — aromatic intensity in an elegant format.', 'Diblong Shot', 'A compact experience — aromatic intensity in an elegant format.', 'https://diblong.com/assets/images/shot-yazi-yani.webp', '/en/product/diblong-shot');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('24c24b5b-31a0-40a9-8dd3-9093390c8312', 'b7b04cbf-1ecc-4979-848c-fad81e474084', 'hr', 'Diblong Shot', 'diblong-shot', 'Kompaktno iskustvo — aromatična intenzivnost u elegantnom formatu.', '<p>Shot format brza priprema i diskretno uživanje. Glatka tekstura, uravnotežen okus, premium ton.', 'Konumirajte iz bočice. Preporuka: jedna porcija po prigodi.', NULL, 'Nije prikladno za trudnoće i maloljetnike. Posavjetujte se s liječnikom.', 'Diblong Shot | Diblong', 'Kompaktno iskustvo — aromatična intenzivnost u elegantnom formatu.', 'Diblong Shot', 'Kompaktno iskustvo — aromatična intenzivnost u elegantnom formatu.', 'https://diblong.com/assets/images/shot-yazi-yani.webp', '/hr/proizvod/diblong-shot');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('4b7156cd-393f-45b9-a44d-daa05e9ebddd', '24f42c31-9558-4358-a990-c471724df551', 'sl', 'Diblong Power Honey', 'diblong-power-honey', 'Gosta medena tekstura z zeliščnim ozadjem — za počasne trenutke.', '<p>Power Honey združuje sladkobo in globino okusa. Priporočamo uživanje v mirnem okolju, kjer lahko občutite teksturo in aromo brez hitenja.</p>', '1 žlička na priložnost. Ne segrevajte nad 40 °C.', NULL, 'Vsebuje med — ni primeren za alergike na cvetni prah.', 'Diblong Power Honey | Diblong', 'Gosta medena tekstura z zeliščnim ozadjem — za počasne trenutke.', 'Diblong Power Honey', 'Gosta medena tekstura z zeliščnim ozadjem — za počasne trenutke.', 'https://diblong.com/assets/images/honey/k1.webp', '/sl/izdelek/diblong-power-honey');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('f85b37ff-ec1c-4bcc-9b6a-ee7162cef945', '24f42c31-9558-4358-a990-c471724df551', 'en', 'Diblong Power Honey', 'diblong-power-honey', 'Rich honey texture with a herbal backdrop — for slow moments.', '<p>Power Honey combines sweetness and depth. Best enjoyed calmly, noticing texture and aroma.</p>', 'One teaspoon per occasion. Do not heat above 40 °C.', NULL, 'Contains honey — not suitable for pollen allergy.', 'Diblong Power Honey | Diblong', 'Rich honey texture with a herbal backdrop — for slow moments.', 'Diblong Power Honey', 'Rich honey texture with a herbal backdrop — for slow moments.', 'https://diblong.com/assets/images/honey/k1.webp', '/en/product/diblong-power-honey');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('13d30b8d-a0cd-49bc-b68b-1a168294465c', '24f42c31-9558-4358-a990-c471724df551', 'hr', 'Diblong Power Honey', 'diblong-power-honey', 'Gusta medena tekstura s biljnim pozadinskim tonom — za sporije trenutke.', '<p>Power Honey spaja slatkoću i dubinu. Najbolje uživati smireno, uz pažnju na teksturu i aromu.</p>', '1 žličica po prigodi. Ne zagrijavajte iznad 40 °C.', NULL, 'Sadrži med — nije prikladno za alergiju na pelud.', 'Diblong Power Honey | Diblong', 'Gusta medena tekstura s biljnim pozadinskim tonom — za sporije trenutke.', 'Diblong Power Honey', 'Gusta medena tekstura s biljnim pozadinskim tonom — za sporije trenutke.', 'https://diblong.com/assets/images/honey/k1.webp', '/hr/proizvod/diblong-power-honey');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('06875822-3295-4204-b597-bf0621659aec', 'be88a6c0-08e6-47bb-98f4-3da25fca7bc7', 'sl', 'Diblong Herbal Paste', 'diblong-zeliscna-pasta', 'Kremasta pasta za ritual nanašanja in zaznavno bogatejšo teksturo.', '<p>Pasta oblika omogoča postopen nadzor količine. Zeliščni profil je zmeren, da ostane eleganten in ne vsiljiv.</p>', 'Nanesite z čisto žličko. Po uporabi zaprite posodo.', NULL, 'Hranite na suhem in hladnem mestu.', 'Diblong Herbal Paste | Diblong', 'Kremasta pasta za ritual nanašanja in zaznavno bogatejšo teksturo.', 'Diblong Herbal Paste', 'Kremasta pasta za ritual nanašanja in zaznavno bogatejšo teksturo.', NULL, '/sl/izdelek/diblong-zeliscna-pasta');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('230e528d-2ed5-40ea-827b-8b959a616602', 'be88a6c0-08e6-47bb-98f4-3da25fca7bc7', 'en', 'Diblong Herbal Paste', 'diblong-herbal-paste', 'Creamy paste for a tactile ritual and richer mouthfeel.', '<p>Paste format gives gradual control. Herbal profile stays moderate and refined.</p>', 'Apply with a clean spoon. Reseal after use.', NULL, 'Store cool and dry.', 'Diblong Herbal Paste | Diblong', 'Creamy paste for a tactile ritual and richer mouthfeel.', 'Diblong Herbal Paste', 'Creamy paste for a tactile ritual and richer mouthfeel.', NULL, '/en/product/diblong-herbal-paste');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('84c8752f-ead0-4486-b107-7bcb0af0aae9', 'be88a6c0-08e6-47bb-98f4-3da25fca7bc7', 'hr', 'Diblong biljna pasta', 'diblong-biljna-pasta', 'Kremasta pasta za ritual nanošenja i bogatiju teksturu.', '<p>Format paste omogućuje postepenu kontrolu količine. Biljni profil ostaje umjeren i elegantan.</p>', 'Nanesite čistom žličicom. Zatvorite nakon upotrebe.', NULL, 'Čuvati suho i rashlađeno.', 'Diblong biljna pasta | Diblong', 'Kremasta pasta za ritual nanošenja i bogatiju teksturu.', 'Diblong biljna pasta', 'Kremasta pasta za ritual nanošenja i bogatiju teksturu.', NULL, '/hr/proizvod/diblong-biljna-pasta');
INSERT INTO public."ProductTranslation" (id, "productId", locale, title, slug, "shortDescription", "longDescription", "usageNotes", "faqJson", disclaimer, "metaTitle", "metaDescription", "ogTitle", "ogDescription", "ogImageUrl", "canonicalPath") VALUES ('6c097b96-a98a-4b11-9315-01f79eea1269', 'e5dd4d78-cc89-4099-9756-f18c1817e3ea', 'sl', 'Diblong Bonbon', 'diblong-bonbon', 'Elegantna sladica z zeliščnim jedrom — diskreten format.', '<p>Bonbon združuje čokoladno tančico in noto, ki ostane subtilna. Priporočamo hranjenje pri sobni temperaturi stran od sončne svetlobe.</p>', '1 kos na priložnost. Uživajte počasi.', NULL, 'Vsebuje sladkor in mlečne sestavine.', 'Diblong Bonbon | Diblong', 'Elegantna sladica z zeliščnim jedrom — diskreten format.', 'Diblong Bonbon', 'Elegantna sladica z zeliščnim jedrom — diskreten format.', 'https://diblong.com/assets/images/bonbon-yazi-yani.webp', '/sl/izdelek/diblong-bonbon');
